    if (!u) return null;

    const withScheme = /^https?:\/\//i.test(u) ? u : ('https://' + u);

    try {
      const host = new URL(withScheme).hostname.toLowerCase();
      return host.replace(/^www\./, '');
    } catch (e) {
      return u
        .toLowerCase()
        .replace(/^https?:\/\//, '')
        .replace(/\/.*$/, '')
        .replace(/^www\./, '')
        .trim() || null;
    }
  })()
}}

