// Clean up markdown/text from the AI output
const raw = items[0].json.output;
let clean = raw;

// Remove markdown fences
if (typeof raw === 'string') {
  clean = raw.replace(/```json/g, '').replace(/```/g, '');

  // Extract just the JSON object (find first { and last })
  const firstOpen = clean.indexOf('{');
  const lastClose = clean.lastIndexOf('}');
  if (firstOpen !== -1 && lastClose !== -1) {
    clean = clean.substring(firstOpen, lastClose + 1);
  }

  try {
    return [{ json: { output: JSON.parse(clean) } }];
  } catch (e) {
    // If parse fails, return raw to debug
    return [{ json: { output: raw, error: "Parse Failed" } }];
  }
}

return items;

// Loop over all 7 agent results
const results = items.map(item => {
  let raw = item.json.output;

  if (typeof raw === 'string') {
    let clean = raw.replace(/```json/g, '').replace(/```/g, '').trim();
    const firstCurly = clean.indexOf('{');
    const lastCurly = clean.lastIndexOf('}');
    if (firstCurly !== -1 && lastCurly !== -1) {
      clean = clean.substring(firstCurly, lastCurly + 1);
    }
    try {
      return { json: { output: JSON.parse(clean) } };
    } catch (e) {
      return { json: { output: { agent: "Error Parsing Agent", error: "Agent returned invalid JSON", raw_content: raw } } };
    }
  }
  return item;
});

return results;
